export default function Play() {
  const canvasRef   = useRef<HTMLCanvasElement>(null);
  const gridRef     = useRef<(PxData|null)[]>(Array(GRID*GRID).fill(null));
  const ownedRef    = useRef(0);

  const [lang,      setLang_]     = useState<Lang>('en');

  const T = useCallback((key: Parameters<typeof t>[1], vars?: Parameters<typeof t>[2]) =>
    t(lang, key, vars), [lang]);

  // Wrap non-Latin characters (CJK, Cyrillic, Korean, Japanese…) in a span
  // shifted up by `px` pixels to correct for baseline mismatch vs Press Start 2P.
  const shiftNonLatin = useCallback((text: string, px = -2): React.ReactNode => {
    const parts = text.split(/([^\u0000-\u024F\u2600-\u26FF\u2700-\u27BF]+)/);
    return parts.map((part, i) =>
      /[^\u0000-\u024F\u2600-\u26FF\u2700-\u27BF]/.test(part)
        ? <span key={i} style={{position:"relative",top:`${px}px`}}>{part}</span>
        : part
    );
  }, []);

  useEffect(() => { setLang_(getLang()); }, []);

  const [color,     setColor]     = useState(PALETTE[6]);
  const [balance,   setBalance]   = useState(0);
  const [owned,     setOwned]     = useState(0);
  const [placed,    setPlaced]    = useState(0);
  const [strike,    setStrike]    = useState<{tier:StrikeTier;earn:number}|null>(null);
  const [hovered,   setHovered]   = useState<{x:number;y:number;d:PxData|null}|null>(null);
  const [profilePopup, setProfilePopup] = useState<{x:number;y:number;owner:string;canvasX:number;canvasY:number}|null>(null);
  const hoverTimerRef = useRef<ReturnType<typeof setTimeout>|null>(null);
  const canvasWrapRef = useRef<HTMLDivElement>(null);
  const [log,       setLog]       = useState<string[]>([T('log_welcome')]);
  const [walletConnected, setWalletConnected] = useState(false);
  const [connecting, setConnecting] = useState(false);
  const [topUpOpen,  setTopUpOpen]  = useState(false);
  const [topUpFlash, setTopUpFlash] = useState(false);
  const [sol,       setSol]       = useState(SOL_START);
  const [canvasPrice, setCanvasPrice] = useState(0.01423);
  const [bucket,    setBucket]    = useState(9221732);       // $CANVAS jackpot
  const [players,   setPlayers]   = useState(1247);
  const [pixelsTotal, setPixelsTotal] = useState(834920);
  const [solEarned, setSolEarned] = useState(12847.382);
  const [miningPct, setMiningPct] = useState(12.32);
  const [solWin,    setSolWin]    = useState<{mult:number;label:string;amount:number}|null>(null);
  const [bucketWin, setBucketWin] = useState<number|null>(null);
  const [betIdx,    setBetIdx]    = useState<BetIdx>(0);   // 0=0.01, 1=0.1, 2=1 SOL

  // ── Pixel-placement animation overlay ─────────────────────────────────────
  type AnimEntry = { x:number; y:number; color:string; tier:StrikeTier|'none'; start:number; dur:number; };
  const overlayRef = useRef<HTMLCanvasElement>(null);
  const animsRef   = useRef<AnimEntry[]>([]);
  const rafRef     = useRef<number>(0);

  const draw = useCallback(() => {
    const c = canvasRef.current; if(!c) return;
    const ctx = c.getContext("2d")!;
    const img = ctx.createImageData(GRID, GRID);
    const buf = img.data;
    for (let i = 0; i < GRID*GRID; i++) {
      const p = gridRef.current[i];
      const off = i * 4;
      if (p) {
        const hex = p.color.replace("#","");
        buf[off]   = parseInt(hex.slice(0,2),16);
        buf[off+1] = parseInt(hex.slice(2,4),16);
        buf[off+2] = parseInt(hex.slice(4,6),16);
        buf[off+3] = 255;
      } else {
        buf[off]=15; buf[off+1]=15; buf[off+2]=30; buf[off+3]=255;
      }
    }
    ctx.putImageData(img, 0, 0);
  },[]);

  // Seed canvas with preset artwork
  useEffect(() => {
    const g = gridRef.current;
    seedCanvas(g);
    assignRandomOwners(g);
    draw();
  },[draw]);

  // Timer: hold rewards + bucket growth
  useEffect(() => {
    const t = setInterval(() => {
      setBalance(b => b + ownedRef.current * HOLD_REWARD_RATE);
      setBucket(bk => bk + 0.5);
      // Simulate small price tick
      setCanvasPrice(p => Math.max(0.001, p + (Math.random() - 0.498) * 0.00008));
      // Global stats tickers
      if (Math.random() < 0.12) setPlayers(p => p + 1);
      setPixelsTotal(pp => pp + Math.floor(40 + Math.random() * 120));
      setMiningPct(m => Math.min(100, m + 0.00006));
      setSolEarned(s => s + 0.3 + Math.random() * 0.5);
    }, 1000);
    return () => clearInterval(t);
  },[]);

  // Bot activity
  useEffect(() => {
    const t = setInterval(() => {
      const g = gridRef.current;
      const idx = Math.floor(Math.random()*GRID*GRID);
      const cell = g[idx];
      if (cell?.owner === WALLET) return;
      const newOwner = rndOwner();
      const newColor = PALETTE[Math.floor(Math.random()*PALETTE.length)];
      g[idx] = { color:newColor, owner:newOwner };
      const c = canvasRef.current; if(!c) return;
      const ctx = c.getContext("2d")!;
      const img3 = ctx.createImageData(1, 1);
      const hex3 = newColor.replace("#","");
      img3.data[0]=parseInt(hex3.slice(0,2),16); img3.data[1]=parseInt(hex3.slice(2,4),16);
      img3.data[2]=parseInt(hex3.slice(4,6),16); img3.data[3]=255;
      ctx.putImageData(img3, idx%GRID, Math.floor(idx/GRID));
    }, 300);
    return () => clearInterval(t);
  },[]);

  const handleClick = useCallback((e: React.MouseEvent<HTMLCanvasElement>) => {
    const bet = BET_TIERS[betIdx];
    if (sol < bet.sol) {
      setLog(l => [T('log_broke', {n: bet.sol}), ...l.slice(0,11)]);
      return;
    }
    const rect2 = (e.target as HTMLCanvasElement).getBoundingClientRect();
    const gx = Math.floor((e.clientX-rect2.left)/PX);
    const gy = Math.floor((e.clientY-rect2.top)/PX);
    if (gx<0||gy<0||gx>=GRID||gy>=GRID) return;
    const g = gridRef.current;
    const c = canvasRef.current; if(!c) return;
    const ctx = c.getContext("2d")!;

    // Deduct full bet cost upfront
    setSol(s => s - bet.sol);

    let totalEarn = 0;
    let newOwned = 0;
    let bestTier: StrikeTier = "none";
    let bestEarn = 0;
    let bucketFeed = 0;

    // Single SOL prize roll for the entire bet
    const betPrize = rollSolPrize();
    const totalSolReturn = betPrize.mult * bet.sol;

    // Place bet.pixels pixels in a circle around (gx, gy)
    const circleR = bet.pixels === 1 ? 0 : Math.ceil(Math.sqrt(bet.pixels / Math.PI)) + 1;
    const circleCandidates: { dist: number; px: number; py: number }[] = [];
    for (let cdy = -circleR; cdy <= circleR; cdy++) {
      for (let cdx = -circleR; cdx <= circleR; cdx++) {
        if (cdx*cdx + cdy*cdy > circleR*circleR) continue;
        const cpx = gx + cdx, cpy = gy + cdy;
        if (cpx < 0 || cpy < 0 || cpx >= GRID || cpy >= GRID) continue;
        circleCandidates.push({ dist: cdx*cdx + cdy*cdy, px: cpx, py: cpy });
      }
    }
    circleCandidates.sort((a, b) => a.dist - b.dist);
    const toPlace = circleCandidates.slice(0, bet.pixels);
    // Single $CANVAS roll for the entire bet
    const betTier = rollStrike();
    bestTier = betTier;

    let placed2 = 0;
    for (const { px, py } of toPlace) {
      const pidx = py * GRID + px;
      const prev = g[pidx];
      if (!prev || prev.owner !== WALLET) newOwned++;
      g[pidx] = { color, owner: WALLET };

      const img4 = ctx.createImageData(1, 1);
      const hex4 = color.replace("#","");
      img4.data[0]=parseInt(hex4.slice(0,2),16); img4.data[1]=parseInt(hex4.slice(2,4),16);
      img4.data[2]=parseInt(hex4.slice(4,6),16); img4.data[3]=255;
      ctx.putImageData(img4, px, py);

      if (placed2 === 0) spawnAnim(px, py, color, betTier);
      placed2++;
    }

    // Total $CANVAS earn = one roll result × all pixels placed
    totalEarn = BASE_EARN * strikeBonus(betTier) * placed2;
    bestEarn = totalEarn;
    bucketFeed = totalEarn * BUCKET_FEED_PCT;

    // Batch state updates
    if (newOwned > 0) setOwned(o => { ownedRef.current = o + newOwned; return o + newOwned; });
    setPlaced(p => p + placed2);
    setBalance(b => b + totalEarn);

    if (totalSolReturn > 0) {
      setSol(s => s + totalSolReturn);
      if (betPrize.mult >= 2) {
        setSolWin({ mult: betPrize.mult, label: betPrize.label, amount: totalSolReturn });
        setTimeout(() => setSolWin(null), betPrize.mult >= 5 ? 4000 : 2500);
      }
    }

    setStrike({ tier: bestTier, earn: bestEarn });
    setTimeout(() => setStrike(null), bestTier !== "none" ? 3000 : 1500);

    setBucket(bk => {
      const newBk = bk + bucketFeed;
      if (Math.random() < BUCKET_WIN_CHANCE) {
        const jackpot = Math.floor(newBk * BUCKET_WIN_PCT);
        setBucketWin(jackpot);
        setTimeout(() => setBucketWin(null), 5000);
        setLog(l => [T('log_vault', {n: String(jackpot)}), ...l.slice(0,11)]);
        setBalance(b => b + jackpot);
        return newBk - jackpot;
      }
      return newBk;
    });

    const netSOL = totalSolReturn - bet.sol;
    const solTag = netSOL > 0
      ? `+${netSOL.toFixed(4)} SOL net`
      : netSOL === 0 ? "break-even" : `${netSOL.toFixed(4)} SOL`;
    const logMsg = bestTier !== "none"
      ? T('log_strike',{tier:bestTier.toUpperCase(),n:totalEarn,x:gx,y:gy})
      : T('log_place',{x:gx,y:gy,n:totalEarn});
    setLog(l => [logMsg, ...l.slice(0,11)]);
  },[betIdx, color, sol]);

  // Animation tick (overlay canvas)
  const tickAnims = useCallback(() => {
    const ov = overlayRef.current; if (!ov) return;
    const ctx = ov.getContext('2d')!;
    ctx.clearRect(0, 0, ov.width, ov.height);
    const now = performance.now();
    animsRef.current = animsRef.current.filter(anim => {
      const t = Math.min(1, (now - anim.start) / anim.dur);
      if (t >= 1) return false;
      const hex = anim.color.replace('#','');
      const r = parseInt(hex.slice(0,2),16);
      const g = parseInt(hex.slice(2,4),16);
      const b = parseInt(hex.slice(4,6),16);
      const cx = anim.x + 0.5, cy = anim.y + 0.5;

      // 1. Instant white flash at pixel
      if (t < 0.25) {
        const ft = t / 0.25;
        ctx.fillStyle = `rgba(255,255,255,${(1-ft)*0.95})`;
        ctx.fillRect(anim.x - 2, anim.y - 2, 5, 5);
      }

      // 2. Expanding rings (3 for normal, +2 for rare, +4 for legendary)
      const numRings = anim.tier==='legendary' ? 7 : anim.tier==='rare' ? 5 : 3;
      const maxR     = anim.tier==='legendary' ? 55 : anim.tier==='rare' ? 38 : 22;
      for (let i = 0; i < numRings; i++) {
        const delay  = i * 0.12;
        const ringT  = Math.max(0, (t - delay) / (1 - delay));
        if (ringT <= 0 || ringT >= 1) continue;
        const radius = ringT * maxR;
        const alpha  = (1 - ringT) * 0.85;
        ctx.beginPath();
        ctx.arc(cx, cy, radius, 0, Math.PI * 2);
        ctx.strokeStyle = `rgba(${r},${g},${b},${alpha})`;
        ctx.lineWidth = 1.5;
        ctx.stroke();
      }

      // 3. Pixel sparks (8 directions, pixel-art squares)
      const numSparks = anim.tier==='legendary' ? 16 : anim.tier==='rare' ? 12 : 8;
      const sparkEnd  = 0.75;
      if (t < sparkEnd) {
        const sT     = t / sparkEnd;
        const maxDst = anim.tier==='legendary' ? 30 : anim.tier==='rare' ? 22 : 14;
        const alpha  = (1 - sT) * 0.9;
        for (let i = 0; i < numSparks; i++) {
          const angle = (i / numSparks) * Math.PI * 2;
          const dist  = sT * maxDst;
          const sz    = Math.max(0.8, 2 * (1 - sT * 0.6));
          ctx.fillStyle = `rgba(${r},${g},${b},${alpha})`;
          ctx.fillRect(cx + Math.cos(angle)*dist - sz/2, cy + Math.sin(angle)*dist - sz/2, sz, sz);
        }
        // interleaved white sparks for "sparkle" feel
        for (let i = 0; i < numSparks; i++) {
          const angle = ((i + 0.5) / numSparks) * Math.PI * 2;
          const dist  = sT * maxDst * 0.7;
          const sz    = Math.max(0.5, 1.2 * (1 - sT));
          ctx.fillStyle = `rgba(255,255,255,${alpha * 0.7})`;
          ctx.fillRect(cx + Math.cos(angle)*dist - sz/2, cy + Math.sin(angle)*dist - sz/2, sz, sz);
        }
      }

      // 4. Radial glow for strikes
      if (anim.tier !== 'none' && t < 0.6) {
        const gT    = t / 0.6;
        const gR    = gT * 70;
        const gA    = (1 - gT) * 0.35;
        const goldR = anim.tier==='legendary' ? '255,215,0' : '139,92,246';
        const grad  = ctx.createRadialGradient(cx, cy, 0, cx, cy, gR);
        grad.addColorStop(0, `rgba(${goldR},${gA})`);
        grad.addColorStop(1, 'rgba(0,0,0,0)');
        ctx.beginPath();
        ctx.arc(cx, cy, gR, 0, Math.PI * 2);
        ctx.fillStyle = grad;
        ctx.fill();
      }

      return true;
    });

    if (animsRef.current.length > 0) {
      rafRef.current = requestAnimationFrame(tickAnims);
    } else {
      overlayRef.current?.getContext('2d')?.clearRect(0,0,GRID*PX,GRID*PX);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const spawnAnim = useCallback((x:number, y:number, color:string, tier:StrikeTier|'none') => {
    const dur = tier==='legendary' ? 1600 : tier==='rare' ? 1100 : 650;
    animsRef.current.push({ x, y, color, tier, start: performance.now(), dur });
    if (animsRef.current.length === 1) {
      rafRef.current = requestAnimationFrame(tickAnims);
    }
  }, [tickAnims]);

  const handleMove = useCallback((e: React.MouseEvent<HTMLCanvasElement>) => {
    const rect2 = (e.target as HTMLCanvasElement).getBoundingClientRect();
    const gx = Math.floor((e.clientX-rect2.left)/PX);
    const gy = Math.floor((e.clientY-rect2.top)/PX);
    if (gx<0||gy<0||gx>=GRID||gy>=GRID) { setHovered(null); return; }
    const cell = gridRef.current[gy*GRID+gx];
    setHovered({x:gx, y:gy, d:cell});
    // Clear previous 3s timer on every move — but don't dismiss an open popup
    if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
    // Only restart the profile-popup timer when no popup is currently open
    if (cell && cell.owner !== "art") {
      const clientX = e.clientX;
      const clientY = e.clientY;
      hoverTimerRef.current = setTimeout(() => {
        setProfilePopup({ x: clientX, y: clientY, owner: cell.owner, canvasX: gx, canvasY: gy });
      }, 3000);
    }
  },[]);


  const handleTopUp = (sol: number, label: string) => {
    setSol(s => s + sol);
    setTopUpOpen(false);
    setTopUpFlash(true);
    setTimeout(() => setTopUpFlash(false), 1200);
    setLog(l => [T('log_topup', {label}), ...l.slice(0,11)]);
  };

  const handleConnect = () => {
    setConnecting(true);
    setTimeout(() => {
      setConnecting(false);
      setWalletConnected(true);
      setLog(l => [T('log_wallet'), ...l.slice(0,11)]);
    }, 1200);
  };

  const isHoldr = owned * 12 >= 10000;
  const [isMobile, setIsMobile] = useState(false);
  const [mobileTab, setMobileTab] = useState<'color'|'game'|'stats'|'log'>('color');
  useEffect(() => {
    const check = () => setIsMobile(window.innerWidth < 768);
    check();
    window.addEventListener('resize', check);
    return () => window.removeEventListener('resize', check);
  }, []);
  const holdrProgress = Math.min(100, (owned * 12 / 10000) * 100);

  return (
    <>
    <MouseTrail />
    <BgCanvas opacity={0.18} speedScale={0.12} zIndex={150} />
    <div style={{background:"transparent",height:"100vh",color:"#e2e8f0",fontFamily:"'Share Tech Mono','Courier New',monospace",overflow:"hidden",display:"flex",flexDirection:"column"}}>
      {/* Top bar */}
      <div style={{borderBottom:"1px solid #1e1e3f",padding:"9px 16px",display:"flex",alignItems:"center",justifyContent:"space-between",background:"rgba(7,7,16,0.95)",backdropFilter:"blur(8px)",flexShrink:0}}>
        <Link href="/" style={{textDecoration:"none"}}><span className="logo-sm-hide"><CanvasLogo size="sm" /></span><span className="logo-xs-show"><CanvasLogo size="xs" /></span></Link>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          {/* $CANVAS price → dexscreener */}
          <a
            href="https://dexscreener.com/base/0xdb2de6074f335ddd307336c303dec329514d5265"
            target="_blank" rel="noopener noreferrer"
            className="nav-price-hide"
            style={{display:"flex",alignItems:"center",gap:6,background:"#0d0a18",border:"1px solid #4c1d95",borderRadius:6,padding:"5px 12px",textDecoration:"none"}}
          >
            <span style={{fontSize:11,color:"#7c3aed",letterSpacing:1}}>$CANVAS</span>
            <span style={{fontSize:14,color:"#a78bfa",fontWeight:"bold",letterSpacing:1}}>${canvasPrice.toFixed(5)}</span>
            <span style={{fontSize:10,color:"#4c1d95"}}>↗</span>
          </a>
          {/* Global stats — inline next to price */}
          <div style={{display:isMobile?"none":"flex",alignItems:"center",gap:10,borderLeft:"1px solid #1e1e3f",paddingLeft:12}}>
            <div style={{display:"flex",alignItems:"center",gap:4}}>
              <span style={{fontSize:11,color:"#475569",letterSpacing:1}}>PLAYERS</span>
              <span style={{fontSize:12.5,color:"#38bdf8",fontWeight:"bold"}}>{players.toLocaleString()}</span>
            </div>
            <div style={{width:1,height:10,background:"#1e1e3f"}}/>
            <div style={{display:"flex",alignItems:"center",gap:4}}>
              <span style={{fontSize:11,color:"#475569",letterSpacing:1}}>PIXELS</span>
              <span style={{fontSize:12.5,color:"#a78bfa",fontWeight:"bold"}}>{pixelsTotal.toLocaleString()}</span>
            </div>
            <div style={{width:1,height:10,background:"#1e1e3f"}}/>
            <div style={{display:"flex",alignItems:"center",gap:4}}>
              <span style={{fontSize:11,color:"#475569",letterSpacing:1}}>SOL EARNED</span>
              <span style={{fontSize:12.5,color:"#22c55e",fontWeight:"bold"}}>◎ {solEarned.toFixed(1)}</span>
            </div>
            <div style={{width:1,height:10,background:"#1e1e3f"}}/>
            <div style={{display:"flex",alignItems:"center",gap:5}}>
              <span style={{fontSize:11,color:"#475569",letterSpacing:1}}>$CANVAS MINED</span>
              <div style={{width:56,height:5,background:"#1e1e3f",borderRadius:3,overflow:"hidden"}}>
                <div style={{width:`${miningPct}%`,height:"100%",background:"linear-gradient(90deg,#7c3aed,#a855f7)",borderRadius:3,transition:"width 1s linear"}}/>
              </div>
              <span style={{fontSize:12.5,color:"#a855f7",fontWeight:"bold"}}>{miningPct.toFixed(2)}%</span>
            </div>
          </div>
          {/* Social links */}
          <div style={{display:isMobile?"none":"flex",alignItems:"center",gap:12}}>
            <a href="https://x.com/canvas_game" target="_blank" rel="noopener noreferrer" title="X / Twitter"
               style={{color:"#94a3b8",display:"flex",alignItems:"center",transition:"color 0.15s"}}
               onMouseEnter={e=>(e.currentTarget.style.color="#e2e8f0")}
               onMouseLeave={e=>(e.currentTarget.style.color="#94a3b8")}>
              <svg width="15" height="15" viewBox="0 0 24 24" fill="currentColor">
                <path d="M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-4.714-6.231-5.401 6.231H2.744l7.73-8.835L1.254 2.25H8.08l4.259 5.629L18.244 2.25zm-1.161 17.52h1.833L7.084 4.126H5.117z"/>
              </svg>
            </a>
            <a href="https://t.me/canvas_game" target="_blank" rel="noopener noreferrer" title="Telegram"
               style={{color:"#94a3b8",display:"flex",alignItems:"center",transition:"color 0.15s"}}
               onMouseEnter={e=>(e.currentTarget.style.color="#e2e8f0")}
               onMouseLeave={e=>(e.currentTarget.style.color="#94a3b8")}>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
                <path d="M11.944 0A12 12 0 0 0 0 12a12 12 0 0 0 12 12 12 12 0 0 0 12-12A12 12 0 0 0 12 0a12 12 0 0 0-.056 0zm4.962 7.224c.1-.002.321.023.465.14a.506.506 0 0 1 .171.325c.016.093.036.306.02.472-.18 1.898-.962 6.502-1.36 8.627-.168.9-.499 1.201-.82 1.23-.696.065-1.225-.46-1.9-.902-1.056-.693-1.653-1.124-2.678-1.8-1.185-.78-.417-1.21.258-1.91.177-.184 3.247-2.977 3.307-3.23.007-.032.014-.15-.056-.212s-.174-.041-.249-.024c-.106.024-1.793 1.14-5.061 3.345-.48.33-.913.49-1.302.48-.428-.008-1.252-.241-1.865-.44-.752-.245-1.349-.374-1.297-.789.027-.216.325-.437.893-.663 3.498-1.524 5.83-2.529 6.998-3.014 3.332-1.386 4.025-1.627 4.476-1.635z"/>
              </svg>
            </a>
            <a href="https://github.com/alnany/canvas-demo" target="_blank" rel="noopener noreferrer" title="GitHub"
               style={{color:"#94a3b8",display:"flex",alignItems:"center",transition:"color 0.15s"}}
               onMouseEnter={e=>(e.currentTarget.style.color="#e2e8f0")}
               onMouseLeave={e=>(e.currentTarget.style.color="#94a3b8")}>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
                <path d="M12 .297c-6.63 0-12 5.373-12 12 0 5.303 3.438 9.8 8.205 11.385.6.113.82-.258.82-.577 0-.285-.01-1.04-.015-2.04-3.338.724-4.042-1.61-4.042-1.61C4.422 18.07 3.633 17.7 3.633 17.7c-1.087-.744.084-.729.084-.729 1.205.084 1.838 1.236 1.838 1.236 1.07 1.835 2.809 1.305 3.495.998.108-.776.417-1.305.76-1.605-2.665-.3-5.466-1.332-5.466-5.93 0-1.31.465-2.38 1.235-3.22-.135-.303-.54-1.523.105-3.176 0 0 1.005-.322 3.3 1.23.96-.267 1.98-.399 3-.405 1.02.006 2.04.138 3 .405 2.28-1.552 3.285-1.23 3.285-1.23.645 1.653.24 2.873.12 3.176.765.84 1.23 1.91 1.23 3.22 0 4.61-2.805 5.625-5.475 5.92.42.36.81 1.096.81 2.22 0 1.606-.015 2.896-.015 3.286 0 .315.21.69.825.57C20.565 22.092 24 17.592 24 12.297c0-6.627-5.373-12-12-12"/>
              </svg>
            </a>
          </div>
          {walletConnected ? (
            <div style={{fontSize:12.5,display:"flex",alignItems:"center",gap:6,background:"#0f1a0f",border:"1px solid #166534",borderRadius:6,padding:"5px 12px"}}>
              <div style={{width:6,height:6,background:"#22c55e",borderRadius:"50%"}} />
              <span style={{color:"#22c55e"}}>Demo_7f4…a9c</span>
            </div>
          ) : (
            <button onClick={handleConnect} disabled={connecting} style={{
              fontSize:12.5,padding:"6px 14px",borderRadius:6,fontFamily:"inherit",cursor:"pointer",
              background:connecting?"#1a1a2e":"linear-gradient(135deg,#7c3aed,#a855f7)",
              color:"#fff",border:"none",
            }}>
              {connecting ? T('play_connecting') : T('play_connect')}
            </button>
          )}
          <LangSwitcher lang={lang} onChange={setLang_} />
        </div>
      </div>


      {/* ── MOBILE STATS STRIP (hidden on desktop) ──────────────────────── */}
      {isMobile && (
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"4px 10px",borderBottom:"1px solid #1e1e3f",background:"#070710",flexShrink:0}}>
          <a href="https://dexscreener.com/base/0xdb2de6074f335ddd307336c303dec329514d5265" target="_blank" rel="noopener noreferrer"
            style={{display:"flex",flexDirection:"column",alignItems:"center",gap:1,textDecoration:"none"}}>
            <span style={{fontSize:9,color:"#7c3aed",letterSpacing:0.5}}>$CANVAS</span>
            <span style={{fontSize:11,color:"#a78bfa",fontWeight:"bold"}}>${canvasPrice.toFixed(5)}</span>
          </a>
          <div style={{width:1,height:20,background:"#1e1e3f"}}/>
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:1}}>
            <span style={{fontSize:9,color:"#475569",letterSpacing:0.5}}>PLAYERS</span>
            <span style={{fontSize:11,color:"#38bdf8",fontWeight:"bold"}}>{fmtCompact(players)}</span>
          </div>
          <div style={{width:1,height:20,background:"#1e1e3f"}}/>
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:1}}>
            <span style={{fontSize:9,color:"#475569",letterSpacing:0.5}}>PIXELS</span>
            <span style={{fontSize:11,color:"#22d3ee",fontWeight:"bold"}}>{fmtCompact(pixelsTotal)}</span>
          </div>
          <div style={{width:1,height:20,background:"#1e1e3f"}}/>
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:1}}>
            <span style={{fontSize:9,color:"#475569",letterSpacing:0.5}}>SOL</span>
            <span style={{fontSize:11,color:"#a3e635",fontWeight:"bold"}}>◎{fmtCompact(Math.floor(solEarned))}</span>
          </div>
          <div style={{width:1,height:20,background:"#1e1e3f"}}/>
          <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:1}}>
            <span style={{fontSize:9,color:"#475569",letterSpacing:0.5}}>MINED</span>
            <span style={{fontSize:11,color:"#a855f7",fontWeight:"bold"}}>{miningPct.toFixed(1)}%</span>
          </div>
        </div>
      )}

      {/* Controls consolidated into bottom color tab */}
      <div style={{display:"flex",flex:1,minHeight:0}}>
        {/* LEFT PANEL */}
        <div style={{width:188,borderRight:"1px solid #1e1e3f",padding:12,display:isMobile?"none":"flex",flexDirection:"column",gap:10,flexShrink:0,overflowY:"auto",background:"#070710"}}>
          {/* ── THE VAULT (jackpot) ─────────────────────────────────────── */}
          <div style={{
            background:"linear-gradient(135deg,#1c0900,#120800)",
            border:"2px solid #f59e0b",
            borderRadius:10,padding:"12px 14px",
            boxShadow:"0 0 24px rgba(245,158,11,0.35)",
            textAlign:"center",
          }}>
            <style>{`
              @keyframes vaultPulse {
                0%,100% { box-shadow: 0 0 24px rgba(245,158,11,0.35); }
                50%      { box-shadow: 0 0 48px rgba(245,158,11,0.70); }
              }
              @keyframes vaultNum {
                0%   { transform:scale(1); }
                30%  { transform:scale(1.12); }
                100% { transform:scale(1); }
              }
            `}</style>
            <div style={{fontSize:12.5,letterSpacing:3,color:"#92400e",marginBottom:4}}>{T('vault_title')}</div>
            <div style={{
              fontSize:17.5,fontWeight:"bold",color:"#f59e0b",lineHeight:1,
              fontFamily:"'Press Start 2P',monospace",letterSpacing:0,wordBreak:"break-all",
            }}>{String(Math.floor(bucket))}</div>
            <div style={{marginTop:8,height:2,background:"#1c0900",borderRadius:1}}>
              <div style={{height:"100%",background:"linear-gradient(90deg,#f59e0b,#fbbf24)",width:"100%",borderRadius:1,opacity:0.4}}/>
            </div>
            <div style={{fontSize:12.5,color:"#6b4c10",marginTop:5,lineHeight:1.6}}>
              {T('vault_odds')}<br/>{T('vault_win')}
            </div>
          </div>

          {/* SOL Balance + Top Up */}
          <div style={{
            background:"#0a120a",
            border:`1px solid ${topUpFlash?"#a3e635":sol<0.5?"#7f1d1d":"#166534"}`,
            borderRadius:8,padding:12,
            boxShadow:topUpFlash?"0 0 16px rgba(163,230,53,0.5)":sol<0.5?"0 0 8px rgba(239,68,68,0.2)":"none",
            transition:"border-color 0.4s,box-shadow 0.4s",
          }}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
              <div style={{fontSize:12.5,color:"#166534",letterSpacing:1}}>{T('sol_balance')}</div>
              {sol < 0.5 && !topUpOpen && (
                <div style={{fontSize:10,color:"#ef4444",letterSpacing:1,animation:"pulse 1.5s infinite"}}>
                  {T('sol_low')}
                  <style>{`@keyframes pulse{0%,100%{opacity:1}50%{opacity:0.4}}`}</style>
                </div>
              )}
            </div>
            <div style={{fontSize:27.5,fontWeight:"bold",color:topUpFlash?"#a3e635":"#22c55e",lineHeight:1,transition:"color 0.4s"}}>
              {sol.toFixed(4)}
            </div>
            <div style={{fontSize:12.5,color:"#166534",marginTop:3}}>
              {BET_TIERS[betIdx].sol} SOL → {BET_TIERS[betIdx].pixels}px
            </div>

            {/* Top Up toggle */}
            <button onClick={()=>setTopUpOpen(o=>!o)} style={{
              marginTop:8,width:"100%",padding:"5px 0",borderRadius:6,
              fontSize:11,fontWeight:"bold",fontFamily:"inherit",letterSpacing:1,
              background:topUpOpen?"#0d1a0d":"linear-gradient(135deg,#14532d,#166534)",
              color:topUpOpen?"#475569":"#bbf7d0",
              border:`1px solid ${topUpOpen?"#1e2e1e":"#166534"}`,
              cursor:"pointer",
            }}>
              {topUpOpen ? T('close') : T('add_sol')}
            </button>

            {topUpOpen && (
              <div style={{marginTop:8,display:"flex",flexDirection:"column",gap:5}}>
                {TOP_UP_PACKS.map(pack => (
                  <button key={pack.sol} onClick={()=>handleTopUp(pack.sol, pack.label)}
                    style={{
                      position:"relative",display:"flex",justifyContent:"space-between",alignItems:"center",
                      padding:"7px 9px",borderRadius:6,fontFamily:"inherit",cursor:"pointer",fontSize:11,
                      background:pack.popular?"#0a1f0a":"#080f08",
                      border:pack.popular?"1px solid #166534":"1px solid #0e1f0e",
                      color:"#e2e8f0",
                    }}>
                    {pack.popular && (
                      <span style={{position:"absolute",top:-7,right:6,fontSize:9,background:"#166534",color:"#bbf7d0",padding:"1px 5px",borderRadius:3,letterSpacing:1}}>
                        {T('pack_popular')}
                      </span>
                    )}
                    <span style={{color:"#22c55e",fontWeight:"bold"}}>{pack.label}</span>
                    <span style={{color:"#334155"}}>{pack.tag}</span>
                  </button>
                ))}
                <div style={{fontSize:10,color:"#14532d",textAlign:"center",marginTop:2}}>
                  {T('top_up_demo')}
                </div>
              </div>
            )}
          </div>

          {/* Balance */}
          <div style={{background:"#0d0d1a",border:"1px solid #2d1b69",borderRadius:8,padding:12}}>
            <div style={{fontSize:12.5,color:"#64748b",marginBottom:4,letterSpacing:1}}>{T('canvas_balance')}</div>
            <div style={{fontSize:32.5,fontWeight:"bold",color:"#a855f7",lineHeight:1}}>{String(Math.floor(balance))}</div>
            {owned > 0 && (
              <div style={{fontSize:12.5,color:"#6d28d9",marginTop:3}}>
                +{(owned*HOLD_REWARD_RATE*60).toFixed(3)}{T('per_min_hold')}
              </div>
            )}
          </div>

          {/* Brush Size */}
          <div style={{background:"#0d0d1a",border:"1px solid #2d1b69",borderRadius:8,padding:12}}>
            <div style={{fontSize:12.5,color:"#64748b",marginBottom:8,letterSpacing:1}}>{T('brush_size')}</div>
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              {(BET_TIERS as unknown as typeof BET_TIERS[number][]).map((tier, i) => {
                const active = betIdx === i;
                const canAfford = sol >= tier.sol;
                return (
                  <button key={i} onClick={() => setBetIdx(i as BetIdx)} style={{
                    display:"flex",justifyContent:"space-between",alignItems:"center",
                    padding:"7px 10px",borderRadius:6,cursor:"pointer",
                    border:`1px solid ${active?"#7c3aed":"#1e1e3f"}`,
                    background:active?"linear-gradient(135deg,#1e0a3e,#2d1b69)":"#0a0a14",
                    opacity: canAfford ? 1 : 0.4,
                  }}>
                    <span style={{fontSize:12.5,color:active?"#a855f7":"#475569",fontWeight:active?"bold":"normal"}}>
                      {tier.label}
                    </span>
                    <span style={{fontSize:12.5,color:active?"#7c3aed":"#334155",background:"#12121a",
                      padding:"2px 6px",borderRadius:3,border:`1px solid ${active?"#4c1d95":"#1e1e3f"}`}}>
                      {tier.tag}
                    </span>
                  </button>
                );
              })}
            </div>
            <div style={{marginTop:8,fontSize:12.5,color:"#334155",lineHeight:1.6}}>
              <span style={{color:"#a855f7"}}>{BET_TIERS[betIdx].sol} SOL</span>
              {" · "}{BET_TIERS[betIdx].pixels} pixel{BET_TIERS[betIdx].pixels>1?"s":""}
            </div>
          </div>

          {/* Stats */}
          <div style={{background:"#0d0d1a",border:"1px solid #1e1e3f",borderRadius:8,padding:12,fontSize:14}}>
            <div style={{color:"#64748b",marginBottom:8,fontSize:12.5,letterSpacing:1}}>{T('your_stats')}</div>
            {([
              [T('pixels_owned'), owned],
              [T('total_placed'), placed],
            ] as [string,number][]).map(([k,v]) => (
              <div key={k} style={{display:"flex",justifyContent:"space-between",marginBottom:5}}>
                <span style={{color:"#475569"}}>{k}</span>
                <span style={{color:"#22d3ee"}}>{v}</span>
              </div>
            ))}
            <div style={{marginTop:8}}>
              <div style={{display:"flex",justifyContent:"space-between",marginBottom:4}}>
                <span style={{fontSize:12.5,color:"#475569"}}>{T('holdr_status')}</span>
                <span style={{fontSize:12.5,color:isHoldr?"#a855f7":"#334155"}}>{isHoldr?T('holdr_check'):`${Math.floor(holdrProgress)}%`}</span>
              </div>
              <div style={{height:3,background:"#1e1e2e",borderRadius:2}}>
                <div style={{height:"100%",background:isHoldr?"#a855f7":"#4c1d95",width:`${holdrProgress}%`,borderRadius:2,transition:"width 0.3s"}}/>
              </div>
              {!isHoldr && (
                <div style={{fontSize:12.5,color:"#334155",marginTop:3}}>{T('holdr_need')} {String(10000-Math.floor(owned*12))} {T('holdr_more')}</div>
              )}
            </div>
          </div>

          {/* Withdraw info */}
          <div style={{background:"#0a0a12",border:"1px solid #1a1a30",borderRadius:8,padding:10,fontSize:12.5,color:"#334155",lineHeight:1.8}}>
            <div style={{color:"#475569",marginBottom:2,letterSpacing:1,fontSize:12.5}}>{T('withdraw_title')}</div>
            {T('withdraw_desc')}<br/>
            {T('withdraw_tax')} <span style={{color:"#6d28d9"}}>{T('withdraw_holdr')}</span><br/>
            {T('withdraw_passive')}
          </div>
        </div>

        {/* CANVAS CENTER */}
        <div ref={canvasWrapRef} style={{flex:1,display:"flex",alignItems:isMobile?"flex-start":"center",justifyContent:isMobile?"flex-start":"center",position:"relative",overflow:"auto",background:"radial-gradient(ellipse at center,#0d0d20,#070710)"}}>

          {/* Vault jackpot popup */}
          {bucketWin !== null && (() => {
            const TOKENS = ["🪙","💰","✨","⭐","💎","🌟","🔥","🎰","💸","🏆"];
            const particles = Array.from({length:80}, (_,i) => {
              const angle = (i/80)*Math.PI*2 + (i%3)*0.15;
              const dist  = 180 + (i%5)*110;
              return {
                tx: Math.cos(angle)*dist, ty: Math.sin(angle)*dist,
                rot: (i%2===0?1:-1)*(180+i*7),
                delay: (i%8)*0.06,
                dur: 1.0 + (i%5)*0.25,
                size: 14 + (i%4)*8,
                tok: TOKENS[i%TOKENS.length],
              };
            });
            return (
              <>
                <style>{`
                  @keyframes vaultFlash   { 0%{opacity:0} 8%{opacity:0.55} 100%{opacity:0} }
                  @keyframes tokenFly     { 0%{opacity:1;transform:translate(0,0) scale(1) rotate(0deg)} 100%{opacity:0;transform:translate(var(--vtx),var(--vty)) scale(0.2) rotate(var(--vrot))} }
                  @keyframes vaultBoom    { 0%{opacity:0;transform:translate(-50%,-50%) scale(0.2)} 12%{opacity:1;transform:translate(-50%,-50%) scale(1.25)} 20%{transform:translate(-50%,-50%) scale(0.95)} 80%{opacity:1;transform:translate(-50%,-50%) scale(1)} 100%{opacity:0;transform:translate(-50%,-50%) scale(0.85)} }
                  @keyframes vaultShake   { 0%,100%{transform:none} 15%{transform:translate(-6px,4px)} 30%{transform:translate(6px,-4px)} 45%{transform:translate(-4px,3px)} 60%{transform:translate(4px,-3px)} 75%{transform:translate(-2px,2px)} }
                `}</style>

                {/* Screen flash */}
                <div style={{position:"fixed",inset:0,zIndex:98,pointerEvents:"none",
                  background:"radial-gradient(ellipse at center,rgba(245,158,11,0.55),transparent 70%)",
                  animation:"vaultFlash 1.2s ease-out forwards"}} />

                {/* Token particles */}
                {particles.map((p,i) => (
                  <div key={i} style={{
                    position:"fixed",left:"50%",top:"50%",
                    fontSize:p.size,pointerEvents:"none",zIndex:99,userSelect:"none",
                    "--vtx":`${p.tx}px`,"--vty":`${p.ty}px`,"--vrot":`${p.rot}deg`,
                    animation:`tokenFly ${p.dur}s ${p.delay}s cubic-bezier(0.1,0.8,0.3,1) forwards`,
                  } as React.CSSProperties}>{p.tok}</div>
                ))}

                {/* Central popup */}
                <div style={{position:"fixed",top:"50%",left:"50%",zIndex:100,
                  pointerEvents:"none",textAlign:"center",
                  animation:"vaultBoom 5s ease-out forwards, vaultShake 0.5s ease-out forwards"}}>
                  <div style={{
                    padding:"28px 52px",borderRadius:20,
                    background:"linear-gradient(135deg,#1c0900,#2d1200)",
                    border:"3px solid #f59e0b",
                    boxShadow:"0 0 160px rgba(245,158,11,1),0 0 60px rgba(251,191,36,0.9),inset 0 0 40px rgba(245,158,11,0.15)",
                    fontFamily:"'Press Start 2P','Noto Sans SC','Noto Sans KR','Noto Sans JP',monospace",
                    whiteSpace:"nowrap",
                    width:"max-content",
                    maxWidth:"min(90vw, 420px)",
                    display:"flex",flexDirection:"column",alignItems:"center",gap:0,
                  }}>
                    <div style={{fontSize:14,color:"#f59e0b",marginBottom:10,letterSpacing:4,lineHeight:1.4,textAlign:"center"}}>{shiftNonLatin(T('vault_cracked'))}</div>
                    <div style={{fontSize:47.5,color:"#fbbf24",fontWeight:"bold",lineHeight:1.2,textAlign:"center",
                      textShadow:"0 0 30px rgba(251,191,36,1),0 0 60px rgba(245,158,11,0.8)"}}>+{String(bucketWin)}</div>
                    <div style={{fontSize:12.5,color:"#92400e",marginTop:8,lineHeight:1.4,textAlign:"center"}}>{shiftNonLatin(T('vault_subtitle'))}</div>
                  </div>
                </div>
              </>
            );
          })()}

          {/* SOL Win popup */}
          {solWin !== null && solWin.mult >= 2 && (
            <div style={{
              position:"absolute",bottom:"20%",left:"50%",
              transform:"translate(-50%,0)",
              zIndex:22,textAlign:"center",pointerEvents:"none",
            }}>
              <style>{`
                @keyframes solWinIn {
                  0%   { opacity:0; transform:translate(-50%,20px) scale(0.7); }
                  15%  { opacity:1; transform:translate(-50%,-8px) scale(1.08); }
                  75%  { opacity:1; transform:translate(-50%,0) scale(1); }
                  100% { opacity:0; transform:translate(-50%,-15px) scale(0.9); }
                }
              `}</style>
              <div style={{
                padding:"14px 30px",borderRadius:12,
                background:"#0a150a",border:`2px solid ${solWin.mult>=10?"#22c55e":"#4ade80"}`,
                boxShadow:`0 0 ${solWin.mult>=10?"80px":"40px"} rgba(34,197,94,${solWin.mult>=10?0.8:0.4})`,
                fontFamily:"'Press Start 2P','Noto Sans SC','Noto Sans KR','Noto Sans JP',monospace",
                animation:"solWinIn 2.5s ease-out forwards",
                whiteSpace:"nowrap",
                width:"max-content",
                maxWidth:"min(90vw, 380px)",
                display:"flex",flexDirection:"column",alignItems:"center",gap:0,
              }}>
                <div style={{fontSize:12.5,color:"#4ade80",marginBottom:6,letterSpacing:2,lineHeight:1.4,textAlign:"center"}}>{shiftNonLatin(`${T('sol_win_label')} ${solWin.label}`)}</div>
                <div style={{fontSize:30,color:"#22c55e",fontWeight:"bold",lineHeight:1.2,textAlign:"center"}}>+{solWin.amount.toFixed(4)}</div>
                <div style={{fontSize:12.5,color:"#166534",marginTop:4,lineHeight:1.4,textAlign:"center"}}>{shiftNonLatin(T('sol_returned'))}</div>
              </div>
            </div>
          )}

          {/* Earnings / Strike popup */}
          {strike && (() => {
            if (strike.tier === "none") {
              return (
                <div style={{position:"absolute",top:"50%",left:"50%",
                  transform:"translate(-50%,-60%)",zIndex:20,textAlign:"center",pointerEvents:"none"}}>
                  <style>{`
                    @keyframes earnIn {
                      0%   { opacity:0; transform:translate(-50%,-70%) scale(0.8); }
                      20%  { opacity:1; transform:translate(-50%,-60%) scale(1.05); }
                      70%  { opacity:1; transform:translate(-50%,-55%) scale(1); }
                      100% { opacity:0; transform:translate(-50%,-45%) scale(0.9); }
                    }
                  `}</style>
                  <div style={{
                    padding:"8px 18px",borderRadius:8,
                    background:"rgba(15,15,22,0.9)",border:"1px solid #334155",
                    fontFamily:"'Press Start 2P',monospace",
                    animation:"earnIn 1.5s ease-out forwards",
                  }}>
                    <div style={{fontSize:15,color:"#94a3b8",fontWeight:"bold"}}>+{strike.earn}</div>
                    <div style={{fontSize:10,color:"#475569",marginTop:2}}>{T('earn_token')}</div>
                  </div>
                </div>
              );
            }
            const sc = strikeStyle(strike.tier);
            return (
              <div style={{
                position:"absolute",top:"50%",left:"50%",
                transform:"translate(-50%,-60%)",
                zIndex:20,textAlign:"center",pointerEvents:"none",
              }}>
                <style>{`
                  @keyframes strikeIn {
                    0%   { opacity:0; transform:translate(-50%,-80%) scale(0.5); }
                    20%  { opacity:1; transform:translate(-50%,-55%) scale(1.1); }
                    80%  { opacity:1; transform:translate(-50%,-50%) scale(1); }
                    100% { opacity:0; transform:translate(-50%,-40%) scale(0.9); }
                  }
                `}</style>
                <div style={{
                  padding:"18px 36px",borderRadius:14,
                  background:sc.bg,border:`2px solid ${sc.border}`,
                  boxShadow:`0 0 ${strike.tier==="legendary"?"80px":strike.tier==="rare"?"50px":"30px"} ${sc.shadow}`,
                  fontFamily:"'Press Start 2P','Noto Sans SC','Noto Sans KR','Noto Sans JP',monospace",
                  animation:"strikeIn 3s ease-out forwards",
                  whiteSpace:"nowrap",
                  width:"max-content",
                  maxWidth:"min(90vw, 420px)",
                  display:"flex",flexDirection:"column",alignItems:"center",gap:0,
                }}>
                  <div style={{fontSize:12.5,color:sc.text,marginBottom:6,letterSpacing:2,lineHeight:1.4,textAlign:"center"}}>
                    {shiftNonLatin(T('strike_label', {tier: strike.tier.toUpperCase()}))}
                  </div>
                  <div style={{fontSize:35,color:"#ffffff",fontWeight:"bold",lineHeight:1.2,textAlign:"center"}}>+{strike.earn}</div>
                  <div style={{fontSize:12.5,color:sc.text,marginTop:4,lineHeight:1.4,textAlign:"center"}}>{shiftNonLatin(T('strike_base', {mult: String(strikeBonus(strike.tier))}))}</div>
                </div>
              </div>
            );
          })()}

          <div style={{position:"relative"}}>

            <canvas
              ref={overlayRef}
              width={GRID*PX}
              height={GRID*PX}
              style={{
                position:"absolute",inset:0,
                pointerEvents:"none",
                imageRendering:"pixelated",
                zIndex:3,
              }}
            />
            <canvas
              ref={canvasRef}
              width={GRID*PX}
              height={GRID*PX}
              onClick={handleClick}
              onMouseMove={handleMove}
              onMouseLeave={() => {
                setHovered(null);
                if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
                // Do NOT clear profilePopup here — it should stay until user explicitly closes it
              }}
              style={{
                cursor: "crosshair",
                display:"block",
                imageRendering:"pixelated",
                border:"1px solid #1e1e3f",
                borderRadius:4,
                boxShadow:"0 0 60px rgba(88,28,235,0.15)",
              }}
            />

            {/* Coordinate mini-tooltip (always on hover) */}
            {hovered && !profilePopup && (
              <div style={{
                position:"absolute",
                left: Math.min(hovered.x*PX+14, GRID*PX-170),
                top:  Math.max(hovered.y*PX-38, 0),
                background:"#0d0d1a",border:"1px solid #2d1b69",
                borderRadius:6,padding:"5px 10px",
                fontSize:12.5,whiteSpace:"nowrap",pointerEvents:"none",zIndex:5,
              }}>
                ({hovered.x},{hovered.y}) ·{" "}
                {hovered.d
                  ? `${hovered.d.owner===WALLET?T('hover_your'):hovered.d.owner}`
                  : T('hover_empty')}
                {hovered.d && (
                  <span style={{
                    marginLeft:6,display:"inline-block",width:8,height:8,
                    background:hovered.d.color,borderRadius:2,verticalAlign:"middle",
                  }}/>
                )}
                {hovered.d && hovered.d.owner !== "art" && (
                  <span style={{marginLeft:6,color:"#64748b",fontSize:11}}>hold 3s for profile</span>
                )}
              </div>
            )}

            {/* Transparent backdrop (fixed) — click outside to close profile popup */}
            {profilePopup && (
              <div
                style={{position:"fixed",inset:0,zIndex:18,cursor:"default"}}
                onClick={() => setProfilePopup(null)}
              />
            )}

            {/* Profile popup (fires after 3s hover, fixed to cursor) */}
            {profilePopup && (() => {
              const popW = 240;
              const popH = 200;
              const vw = typeof window !== "undefined" ? window.innerWidth  : 1920;
              const vh = typeof window !== "undefined" ? window.innerHeight : 1080;
              const leftPos = profilePopup.x + popW + 24 > vw ? profilePopup.x - popW - 14 : profilePopup.x + 14;
              const topPos  = Math.max(8, Math.min(profilePopup.y - 20, vh - popH - 8));
              const prof = PROFILES[profilePopup.owner] ?? null;
              const isYou = profilePopup.owner === WALLET;
              return (
                <div
                  style={{
                    position:"fixed", left:leftPos, top:topPos,
                    width:popW, background:"#0a0a18",
                    border:"1px solid #7c3aed", borderRadius:10,
                    padding:14, zIndex:20, pointerEvents:"auto",
                    boxShadow:"0 0 24px rgba(124,58,237,0.5)",
                    fontFamily:"inherit",
                  }}
                  onClick={e => e.stopPropagation()}
                  onMouseEnter={() => { if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current); }}
                >
                  {/* Close */}
                  <div
                    onClick={() => setProfilePopup(null)}
                    style={{position:"absolute",top:8,right:10,cursor:"pointer",fontSize:15,color:"#64748b",lineHeight:1}}
                  >x</div>

                  {isYou ? (
                    <div style={{textAlign:"center",paddingTop:8}}>
                      <div style={{fontSize:35,marginBottom:6}}>🎮</div>
                      <div style={{color:"#a78bfa",fontSize:14,fontWeight:"bold"}}>You</div>
                      <div style={{color:"#64748b",fontSize:12.5,marginTop:4}}>This is your pixel</div>
                      <div style={{color:"#475569",fontSize:11,marginTop:6}}>({profilePopup.canvasX}, {profilePopup.canvasY})</div>
                    </div>
                  ) : prof ? (
                    <>
                      {/* Avatar + name */}
                      <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}>
                        <div style={{
                          width:40,height:40,borderRadius:"50%",
                          background:"#1e1b4b",border:"2px solid #7c3aed",
                          display:"flex",alignItems:"center",justifyContent:"center",
                          fontSize:25,flexShrink:0,
                        }}>{prof.avatar}</div>
                        <div>
                          <div style={{color:"#e2e8f0",fontSize:15,fontWeight:"bold"}}>{prof.displayName}</div>
                          <div style={{color:"#64748b",fontSize:11,marginTop:2}}>{prof.handle}</div>
                        </div>
                      </div>

                      {/* Bio */}
                      <div style={{color:"#94a3b8",fontSize:12.5,lineHeight:1.5,marginBottom:10,wordBreak:"break-word"}}>
                        {prof.bio}
                      </div>

                      {/* Stats */}
                      <div style={{display:"flex",gap:12,marginBottom:10}}>
                        <div style={{textAlign:"center"}}>
                          <div style={{color:"#a78bfa",fontSize:14,fontWeight:"bold"}}>{prof.joinedSlot}</div>
                          <div style={{color:"#475569",fontSize:11}}>pixels</div>
                        </div>
                        <div style={{textAlign:"center"}}>
                          <div style={{color:"#22d3ee",fontSize:14,fontWeight:"bold"}}>
                            ({profilePopup.canvasX},{profilePopup.canvasY})
                          </div>
                          <div style={{color:"#475569",fontSize:11}}>this pixel</div>
                        </div>
                      </div>

                      {/* Links */}
                      <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                        {prof.xUrl && (
                          <a
                            href={prof.xUrl}
                            target="_blank"
                            rel="noopener noreferrer"
                            style={{
                              display:"inline-flex",alignItems:"center",gap:4,
                              background:"#18181b",border:"1px solid #3f3f46",
                              borderRadius:6,padding:"4px 8px",
                              color:"#e2e8f0",fontSize:12.5,textDecoration:"none",
                            }}
                          >
                            <span style={{fontSize:15}}>𝕏</span> Twitter
                          </a>
                        )}
                        {prof.homepage && (
                          <a
                            href={prof.homepage}
                            target="_blank"
                            rel="noopener noreferrer"
                            style={{
                              display:"inline-flex",alignItems:"center",gap:4,
                              background:"#18181b",border:"1px solid #3f3f46",
                              borderRadius:6,padding:"4px 8px",
                              color:"#a78bfa",fontSize:12.5,textDecoration:"none",
                            }}
                          >
                            🔗 Site
                          </a>
                        )}
                      </div>
                    </>
                  ) : (
                    /* Unknown wallet */
                    <div style={{textAlign:"center",paddingTop:8}}>
                      <div style={{fontSize:35,marginBottom:6}}>👤</div>
                      <div style={{color:"#94a3b8",fontSize:14}}>{profilePopup.owner}</div>
                      <div style={{color:"#475569",fontSize:11,marginTop:6}}>
                        ({profilePopup.canvasX}, {profilePopup.canvasY}) · no public profile
                      </div>
                    </div>
                  )}
                </div>
              );
            })()}
          </div>
        </div>

        {/* RIGHT PANEL */}
        <div style={{width:196,borderLeft:"1px solid #1e1e3f",padding:12,display:isMobile?"none":"flex",flexDirection:"column",gap:10,flexShrink:0,background:"#070710"}}>
          {/* Color picker */}
          <div>
            <div style={{fontSize:12.5,color:"#64748b",marginBottom:8,letterSpacing:1}}>{T('color_label')}</div>
            <div style={{display:"grid",gridTemplateColumns:"repeat(8,1fr)",gap:2}}>
              {PALETTE.map(c => (
                <button key={c} onClick={() => setColor(c)} style={{
                  width:16,height:16,borderRadius:2,background:c,border:"none",cursor:"pointer",padding:0,
                  outline:color===c?"2px solid #ffffff":"2px solid transparent",
                  outlineOffset:1,transition:"outline 0.1s",
                }}/>
              ))}
            </div>
            {/* Custom color picker */}
            <div style={{marginTop:8,display:"flex",alignItems:"center",gap:6}}>
              <label style={{position:"relative",cursor:"pointer",flexShrink:0}} title="Custom color">
                <div style={{
                  width:24,height:24,borderRadius:4,
                  background:`conic-gradient(red,yellow,lime,cyan,blue,magenta,red)`,
                  border: color && !PALETTE.includes(color) ? "2px solid #fff" : "2px solid #334155",
                  boxShadow: color && !PALETTE.includes(color) ? "0 0 8px rgba(255,255,255,0.5)" : "none",
                  transition:"border 0.15s",
                }}/>
                <input type="color" value={color}
                  onChange={e => setColor(e.target.value)}
                  style={{position:"absolute",inset:0,opacity:0,cursor:"pointer",width:"100%",height:"100%"}}
                />
              </label>
              <div style={{width:14,height:14,borderRadius:3,background:color,flexShrink:0,border:"1px solid #2d1b69"}}/>
              <span style={{color:"#475569",fontSize:12.5}}>{color}</span>
            </div>
          </div>

          {/* Strike tiers */}
          <div style={{background:"#0d0d1a",border:"1px solid #0e2a36",borderRadius:8,padding:10}}>
            <div style={{fontSize:12.5,color:"#64748b",marginBottom:8,letterSpacing:1}}>{T('strike_odds')}</div>
            {[
              {tier:T('strike_common'),  chance:"5%",   mult:"5×",   color:"#64748b"},
              {tier:T('strike_rare'),    chance:"1%",   mult:"25×",  color:"#22d3ee"},
              {tier:T('strike_legendary'),chance:"0.1%",mult:"200×", color:"#f59e0b"},
            ].map(s => (
              <div key={s.tier} style={{display:"grid",gridTemplateColumns:"1fr 2.5rem 2.5rem",alignItems:"center",marginBottom:5,fontSize:12.5,gap:4}}>
                <span style={{color:s.color}}>{s.tier}</span>
                <span style={{color:"#334155",textAlign:"right"}}>{s.chance}</span>
                <span style={{color:s.color,fontWeight:"bold",textAlign:"right"}}>{s.mult}</span>
              </div>
            ))}
            <div style={{marginTop:6,fontSize:12.5,color:"#1e3a4f",lineHeight:1.6}}>
              {T('strike_rng')}
            </div>
          </div>

          {/* Activity log */}
          <div style={{background:"#0d0d1a",border:"1px solid #1e1e3f",borderRadius:8,padding:10,flex:1,overflow:"hidden"}}>
            <div style={{fontSize:12.5,color:"#64748b",marginBottom:8,letterSpacing:1}}>{T('activity_label')}</div>
            <div style={{fontSize:12.5,lineHeight:2,overflow:"hidden"}}>
              {log.slice(0,8).map((l,i) => {
                const logParts = l.split('|');
                const dispText = logParts[0];
                const coordStr = logParts.length > 1 ? logParts[1] : '';
                const hasCoords = coordStr.includes(',');
                const lx = hasCoords ? parseInt(coordStr.split(',')[0], 10) : -1;
                const ly = hasCoords ? parseInt(coordStr.split(',')[1], 10) : -1;
                return (
                <div key={i}
                  onClick={() => {
                    if (!hasCoords) return;
                    spawnAnim(lx, ly, '#a855f7', 'rare');
                    canvasWrapRef.current?.scrollTo({
                      left: Math.max(0, lx - 200),
                      top: Math.max(0, ly - 200),
                      behavior: 'smooth',
                    });
                  }}
                  style={{color:i===0?"#a855f7":hasCoords?"#4a3060":"#334155",cursor:hasCoords?"pointer":"default",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}} title={hasCoords?"Click to highlight pixel":undefined}>{dispText}</div>
              );
              })}
            </div>
          </div>

          {/* Leaderboard */}
          <div style={{background:"#0d0d1a",border:"1px solid #1e1e3f",borderRadius:8,padding:10}}>
            <div style={{fontSize:12.5,color:"#64748b",marginBottom:10,letterSpacing:1}}>{T('top_players')}</div>
            {[
              {addr:"0xaf1…c32", px:1284, earn:24680, isYou:false},
              {addr:"0x7a3…b9f", px:963,  earn:18420, isYou:false},
              {addr:WALLET,      px:owned, earn:Math.floor(balance), isYou:true},
              {addr:"0x99d…441", px:312,  earn:6180,  isYou:false},
              {addr:"0xb82…71a", px:148,  earn:2860,  isYou:false},
            ]
            .sort((a,b)=>b.px-a.px)
            .slice(0,5)
            .map((p,i) => (
              <div key={p.addr}
                onClick={e => setProfilePopup({ x: e.clientX, y: e.clientY, owner: p.addr, canvasX: 0, canvasY: 0 })}
                style={{
                  display:"flex",justifyContent:"space-between",
                  marginBottom:6,fontSize:12.5,
                  color:p.isYou?"#a855f7":i===0?"#f59e0b":"#475569",
                  cursor:"pointer",
                  borderRadius:4,padding:"2px 4px",margin:"-2px -4px 4px",
                  transition:"background 0.15s",
                }}
                onMouseEnter={e=>(e.currentTarget.style.background="rgba(168,85,247,0.08)")}
                onMouseLeave={e=>(e.currentTarget.style.background="transparent")}>
                <span style={{overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",maxWidth:90}}>
                  {i+1}. {p.addr}
                </span>
                <span style={{flexShrink:0,marginLeft:4}}>{p.px}px</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* ── MOBILE BOTTOM TABS (hidden on desktop) ────────────────────── */}
      {isMobile && (
        <div style={{flexShrink:0,borderTop:"1px solid #1e1e3f",background:"#070710",display:"flex",flexDirection:"column",overflow:"hidden",height:290}}>
          {/* Quick-access bar: color swatch + active bet + balances */}
          <div style={{display:"flex",alignItems:"center",gap:8,padding:"6px 12px",borderBottom:"1px solid #0d0d1a",flexShrink:0,background:"#09090f"}}>
            <label style={{position:"relative",cursor:"pointer",flexShrink:0}} title="Color">
              <div style={{width:24,height:24,borderRadius:4,background:color,border:"2px solid #4c1d95",boxSizing:"border-box"}}/>
              <input type="color" value={color} onChange={e=>setColor(e.target.value)}
                style={{position:"absolute",inset:0,opacity:0,cursor:"pointer",width:"100%",height:"100%"}} />
            </label>
            <div style={{display:"flex",gap:4,flex:1,overflow:"hidden"}}>
              {BET_TIERS.map((bet,i) => {
                const active = betIdx === i;
                return (
                  <button key={i} onClick={()=>setBetIdx(i as BetIdx)} style={{
                    flex:1,padding:"4px 0",borderRadius:4,fontSize:10,cursor:"pointer",
                    border:`1px solid ${active?"#7c3aed":"#1e1e3f"}`,
                    background:active?"linear-gradient(135deg,#1e0a3e,#2d1b69)":"#0a0a14",
                    color:active?"#a855f7":"#475569",letterSpacing:0.3,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"
                  }}>{bet.sol} SOL</button>
                );
              })}
            </div>
            <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:0,flexShrink:0}}>
              <span style={{fontSize:9,color:"#64748b"}}>◎ {sol.toFixed(2)}</span>
              <span style={{fontSize:11,color:"#a855f7",fontWeight:"bold"}}>{fmtCompact(Math.floor(balance))} $C</span>
            </div>
          </div>
          {/* Tab bar */}
          <div style={{display:"flex",borderBottom:"1px solid #1e1e3f",flexShrink:0}}>
            {(["color","game","stats","log"] as const).map(tab => {
              const labels:{[k:string]:string} = {color:"🎨 Color",game:"⚡ Game",stats:"👥 Stats",log:"📋 Log"};
              return (
                <button key={tab} onClick={()=>setMobileTab(tab)} style={{
                  flex:1,padding:"6px 0",border:"none",background:"transparent",
                  color:mobileTab===tab?"#a855f7":"#475569",fontSize:10,cursor:"pointer",
                  borderBottom:mobileTab===tab?"2px solid #7c3aed":"2px solid transparent",
                  letterSpacing:0.5
                }}>{labels[tab]}</button>
              );
            })}
          </div>
          {/* Tab content */}
          <div style={{flex:1,overflow:"auto",padding:10}}>
            {/* ── COLOR TAB ── */}
            {mobileTab==="color" && (
              <div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(8,1fr)",gap:3,marginBottom:8}}>
                  {PALETTE.map(c => (
                    <button key={c} onClick={()=>setColor(c)} style={{
                      width:22,height:22,borderRadius:3,background:c,border:"none",cursor:"pointer",padding:0,
                      outline:color===c?"2px solid #fff":"2px solid transparent",outlineOffset:1
                    }}/>
                  ))}
                </div>
                <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}>
                  <label style={{position:"relative",cursor:"pointer",flexShrink:0}}>
                    <div style={{width:26,height:26,borderRadius:4,background:"conic-gradient(red,yellow,lime,cyan,blue,magenta,red)",border:!PALETTE.includes(color)?"2px solid #fff":"2px solid #334155"}}/>
                    <input type="color" value={color} onChange={e=>setColor(e.target.value)}
                      style={{position:"absolute",inset:0,opacity:0,cursor:"pointer",width:"100%",height:"100%"}}/>
                  </label>
                  <div style={{width:16,height:16,borderRadius:3,background:color,border:"1px solid #2d1b69"}}/>
                  <span style={{color:"#475569",fontSize:12.5}}>{color}</span>
                </div>
                <div style={{display:"flex",flexDirection:"column",gap:4}}>
                  {BET_TIERS.map((bet,i) => {
                    const active = betIdx === i;
                    return (
                      <button key={i} onClick={()=>setBetIdx(i as BetIdx)} style={{
                        display:"flex",justifyContent:"space-between",alignItems:"center",
                        padding:"6px 10px",borderRadius:6,border:`1px solid ${active?"#7c3aed":"#1e1e3f"}`,
                        background:active?"linear-gradient(135deg,#1e0a3e,#2d1b69)":"#0a0a14",cursor:"pointer"
                      }}>
                        <span style={{fontSize:12.5,color:active?"#a855f7":"#475569",fontWeight:active?"bold":"normal"}}>{bet.sol} SOL</span>
                        <span style={{fontSize:12.5,color:active?"#7c3aed":"#334155",background:"#12121a",padding:"2px 6px",borderRadius:3,border:`1px solid ${active?"#4c1d95":"#1e1e3f"}`}}>{bet.pixels}px</span>
                      </button>
                    );
                  })}
                </div>
              </div>
            )}
            {/* ── GAME TAB ── */}
            {mobileTab==="game" && (
              <div style={{display:"flex",flexDirection:"column",gap:8}}>
                <div style={{background:"#0a0718",border:"1px solid #4c1d95",borderRadius:8,padding:10}}>
                  <div style={{fontSize:11,color:"#7c3aed",letterSpacing:1,marginBottom:4}}>{T('vault_title')}</div>
                  <div style={{fontSize:20,color:"#a855f7",fontWeight:"bold",letterSpacing:1}}>{bucket.toLocaleString()}</div>
                  <div style={{fontSize:11,color:"#6d28d9",marginTop:2}}>{T('vault_odds')} · {T('vault_win')}</div>
                </div>
                <div style={{background:"#0d0d1a",border:"1px solid #0e2a36",borderRadius:8,padding:10}}>
                  <div style={{fontSize:11,color:"#64748b",marginBottom:6,letterSpacing:1}}>{T('strike_odds')}</div>
                  {[
                    {tier:T('strike_common'),  chance:"5%",  mult:"5×",  col:"#64748b"},
                    {tier:T('strike_rare'),    chance:"1%",  mult:"25×", col:"#22d3ee"},
                    {tier:T('strike_legendary'),chance:"0.1%",mult:"200×",col:"#f59e0b"},
                  ].map(s => (
                    <div key={s.tier} style={{display:"grid",gridTemplateColumns:"1fr 2.5rem 2.5rem",alignItems:"center",marginBottom:4,fontSize:12.5,gap:4}}>
                      <span style={{color:s.col}}>{s.tier}</span>
                      <span style={{color:"#334155",textAlign:"right"}}>{s.chance}</span>
                      <span style={{color:s.col,fontWeight:"bold",textAlign:"right"}}>{s.mult}</span>
                    </div>
                  ))}
                </div>
                <div style={{fontSize:11,color:"#475569",lineHeight:1.8}}>
                  <div style={{display:"flex",justifyContent:"space-between"}}><span>Balance</span><span style={{color:"#94a3b8"}}>{Math.floor(balance)} $CANVAS</span></div>
                  <div style={{display:"flex",justifyContent:"space-between"}}><span>Pixels owned</span><span style={{color:"#94a3b8"}}>{owned}</span></div>
                  <div style={{display:"flex",justifyContent:"space-between"}}><span>Holdr</span><span style={{color:isHoldr?"#a855f7":"#334155"}}>{isHoldr?T('holdr_check'):`${Math.floor(holdrProgress)}%`}</span></div>
                </div>
              </div>
            )}
            {/* ── STATS TAB ── */}
            {mobileTab==="stats" && (
              <div>
                <div style={{fontSize:11,color:"#64748b",marginBottom:8,letterSpacing:1}}>{T('top_players')}</div>
                {[
                  {addr:"0xaf1…c32",px:1284,earn:24680,isYou:false},
                  {addr:"0x7a3…b9f",px:963, earn:18420,isYou:false},
                  {addr:WALLET,     px:owned,earn:Math.floor(balance),isYou:true},
                  {addr:"0x99d…441",px:312, earn:6180, isYou:false},
                  {addr:"0xb82…71a",px:148, earn:2860, isYou:false},
                ]
                .sort((a,b)=>b.px-a.px).slice(0,5)
                .map((p,i) => (
                  <div key={p.addr}
                    onClick={e=>setProfilePopup({x:e.clientX,y:e.clientY,owner:p.addr,canvasX:0,canvasY:0})}
                    style={{display:"flex",justifyContent:"space-between",marginBottom:6,fontSize:12.5,
                      color:p.isYou?"#a855f7":i===0?"#f59e0b":"#475569",cursor:"pointer",
                      borderRadius:4,padding:"2px 4px",margin:"-2px -4px 4px",transition:"background 0.15s"}}
                    onMouseEnter={e=>(e.currentTarget.style.background="rgba(168,85,247,0.08)")}
                    onMouseLeave={e=>(e.currentTarget.style.background="transparent")}>
                    <span style={{overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",maxWidth:130}}>
                      {i+1}. {p.addr}
                    </span>
                    <span style={{flexShrink:0,marginLeft:4}}>{p.px}px</span>
                  </div>
                ))}
                <div style={{marginTop:8,background:"#0d0d1a",borderRadius:6,padding:8}}>
                  <div style={{display:"flex",justifyContent:"space-between",marginBottom:4,fontSize:11,color:"#64748b",letterSpacing:1}}><span>HOLDR PROGRESS</span><span style={{color:isHoldr?"#a855f7":"#334155"}}>{isHoldr?"✓":""+Math.floor(holdrProgress)+"%"}</span></div>
                  <div style={{width:"100%",height:4,background:"#1e1e3f",borderRadius:2,overflow:"hidden"}}>
                    <div style={{height:"100%",background:isHoldr?"#a855f7":"#4c1d95",width:`${holdrProgress}%`,borderRadius:2,transition:"width 0.3s"}}/>
                  </div>
                </div>
              </div>
            )}
            {/* ── LOG TAB ── */}
            {mobileTab==="log" && (
              <div style={{fontSize:12.5,lineHeight:2}}>
                {log.slice(0,10).map((l,i) => {
                  const logParts = l.split('|');
                  const dispText = logParts[0];
                  const coordStr = logParts.length > 1 ? logParts[1] : '';
                  const hasCoords = coordStr.includes(',');
                  const lx = hasCoords ? parseInt(coordStr.split(',')[0],10) : -1;
                  const ly = hasCoords ? parseInt(coordStr.split(',')[1],10) : -1;
                  return (
                    <div key={i}
                      onClick={()=>{
                        if (!hasCoords) return;
                        spawnAnim(lx,ly,'#a855f7','rare');
                        canvasWrapRef.current?.scrollTo({left:Math.max(0,lx-150),top:Math.max(0,ly-150),behavior:'smooth'});
                      }}
                      style={{color:i===0?"#a855f7":hasCoords?"#4a3060":"#334155",cursor:hasCoords?"pointer":"default",
                        whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}
                      title={hasCoords?"Tap to highlight pixel":undefined}>{dispText}</div>
                  );
                })}
              </div>
            )}
          </div>
        </div>
      )}

    </div>
    </>
  );
}
